        private const val SESSION_EXPIRY_MS = 24 * 60 * 60 * 1000L // 24 hours

        @Volatile
        private var instance: SessionTokenGenerator? = null

        fun getInstance(): SessionTokenGenerator {
            return instance ?: synchronized(this) {
                instance ?: SessionTokenGenerator().also { instance = it }
            }
        }
    }

    private fun generateRandomString(length: Int = tokenLength): String {
        val sb = StringBuilder(length)
        for (i in 0 until length) {
            val index = secureRandom.nextInt(alphanumericChars.length)
            sb.append(alphanumericChars[index])
        }
        return sb.toString()
    }

    fun startSession(): String {
        cleanupExpiredTokens()
        currentSessionId = generateRandomString()
        return currentSessionId!!
    }

    fun getCurrentSessionId(): String? = currentSessionId

