    }

    fun generateApiRequestToken(expiryMs: Long = DEFAULT_TOKEN_EXPIRY_MS): String? {
        return generateTemporaryToken(TokenPurpose.API_REQUEST, expiryMs)?.token
    }

    fun generateUploadToken(expiryMs: Long = 30 * 60 * 1000L): String? {
        return generateTemporaryToken(TokenPurpose.FILE_UPLOAD, expiryMs)?.token
    }

    fun generateRefreshToken(expiryMs: Long = SESSION_EXPIRY_MS): String? {
        return generateTemporaryToken(TokenPurpose.REFRESH, expiryMs)?.token
    }

    fun validateToken(token: String): Boolean {
