            .map { it.key to it.value.copy(sessionId = newSessionId) }

        tokensToMigrate.forEach { (key, updatedInfo) ->
            activeTokens[key] = updatedInfo
        }

        currentSessionId = newSessionId
        return newSessionId
    }

    fun getSessionSummary(): Map<String, Any> {
